-- ============================================================================
-- briefing_library_migration  (DRAFT — do not apply without Myke go)
-- Full migration of the Airtable Briefing Library (tbl4kbby85nx6Z891, 436 rows,
-- snapshot 2026-07-18) into Supabase, with linkage to faraday_domains,
-- faraday_subdomains, tracking_companies, and faraday_themes.
-- Source snapshots: docs/briefing-library-migration/*.json (this repo).
-- Mapping rules + code-update spec: docs/briefing-library-migration/README.md
-- Notes:
--  * Airtable statuses: Live / Draft / Coming Soon / 'Retired ' (trailing space
--    trimmed here). Snapshot contained only Coming Soon (357) + Draft (79).
--  * Attachments field was empty on all 436 rows -> attachments jsonb kept for
--    schema completeness, seeded '[]'.
--  * Company links are inserted only when the company exists in
--    tracking_companies (Airtable rec-ID keyed); misses land in unmapped_links.
--  * 'Jurisdiction Posture Intelligence (JPS)' sub-domain and 'The Rack
--    Revolution' theme have no canon code -> preserved in unmapped_links.
-- ============================================================================

begin;

create table if not exists faraday_briefings (
  briefing_id        integer primary key,          -- Airtable autoNumber "Briefing Id"
  airtable_record_id text not null unique,
  title              text not null,
  description        text,
  status             text not null default 'Draft'
                     check (status in ('Live','Draft','Coming Soon','Retired')),
  gamma_url          text,
  gamma_id           text,
  canonical_flag     text,
  download_count     integer not null default 0,
  go_live_date       date,
  attachments        jsonb not null default '[]'::jsonb,
  unmapped_links     jsonb not null default '{}'::jsonb,
  airtable_created_at timestamptz,
  created_at         timestamptz not null default now(),
  updated_at         timestamptz not null default now()
);

create table if not exists faraday_briefing_domains (
  briefing_id integer not null references faraday_briefings(briefing_id) on delete cascade,
  domain_code text    not null references faraday_domains(domain_code),
  primary key (briefing_id, domain_code)
);
create table if not exists faraday_briefing_subdomains (
  briefing_id    integer not null references faraday_briefings(briefing_id) on delete cascade,
  subdomain_code text    not null references faraday_subdomains(subdomain_code),
  primary key (briefing_id, subdomain_code)
);
create table if not exists faraday_briefing_companies (
  briefing_id integer not null references faraday_briefings(briefing_id) on delete cascade,
  company_id  text    not null references tracking_companies(company_id),
  primary key (briefing_id, company_id)
);
create table if not exists faraday_briefing_themes (
  briefing_id integer not null references faraday_briefings(briefing_id) on delete cascade,
  theme_code  text    not null references faraday_themes(theme_code),
  primary key (briefing_id, theme_code)
);

create index if not exists idx_briefings_status on faraday_briefings(status);
create index if not exists idx_briefing_subdomains_code on faraday_briefing_subdomains(subdomain_code);
create index if not exists idx_briefing_companies_company on faraday_briefing_companies(company_id);

-- ── Seed: briefings (436 rows) ──────────────────────────────────────────────
