insert into faraday_briefing_companies (briefing_id, company_id)
select l.briefing_id, l.company_id from _briefing_company_links l
where exists (select 1 from tracking_companies t where t.company_id = l.company_id)
on conflict do nothing;

update faraday_briefings b
set unmapped_links = jsonb_set(b.unmapped_links, '{companies}',
  (select jsonb_agg(jsonb_build_object('id', l.company_id, 'name', l.company_name))
   from _briefing_company_links l
   where l.briefing_id = b.briefing_id
     and not exists (select 1 from tracking_companies t where t.company_id = l.company_id)))
where exists (select 1 from _briefing_company_links l
   where l.briefing_id = b.briefing_id
     and not exists (select 1 from tracking_companies t where t.company_id = l.company_id));

-- ── Non-canon link names preserved (JPS sub-domain, Rack Revolution theme) ──
update faraday_briefings set unmapped_links = '{"themes": ["The Rack Revolution"]}'::jsonb where briefing_id = 9;
update faraday_briefings set unmapped_links = '{"themes": ["The Rack Revolution"]}'::jsonb where briefing_id = 16;
update faraday_briefings set unmapped_links = '{"themes": ["The Rack Revolution"]}'::jsonb where briefing_id = 17;
update faraday_briefings set unmapped_links = '{"subdomains": ["Jurisdiction Posture Intelligence (JPS)"]}'::jsonb where briefing_id = 71;

-- ── Verification ────────────────────────────────────────────────────────────
do $$
declare n int;
begin
  select count(*) into n from faraday_briefings;
  raise notice 'faraday_briefings rows: % (expected 436)', n;
  select count(*) into n from faraday_briefing_subdomains;
  raise notice 'subdomain links: %', n;
  select count(*) into n from faraday_briefing_companies;
  raise notice 'company links kept: % of 366 staged', n;
end $$;

commit;
